        .select('id')
        .eq('id_crianca', p.idCrianca)
        .eq('id_culto', p.idCulto)
        .eq('status', 'pendente')
        .maybeSingle();

      if (existing) return;

      const { error } = await supabase.from(TABLES.PRECHECKINS).insert([{
